// Build the OpenAI chat request from PR-001 + llm settings. No secrets here.
const prow = $('Load PR-001 + LLM Settings').first().json;
const settings = prow.settings;   // jsonb -> already an object            // llm provider settings
const sys = prow.system_prompt || '';
const usr = (prow.user_prompt || '').replace('{{ocr}}', JSON.stringify($('When Executed by WF-001').first().json.ocr));
return [{ json: { _model: settings.model, _temp: settings.temperature ?? 0, _max: settings.maxTokens ?? 4096,
  messages: [ ...(sys?[{role:'system',content:sys}]:[]), {role:'user',content:usr} ] } }];

// Enrichment: preserve incoming item (incl. ocr, metadata), add { knowledge }.
const incoming = $('When Executed by WF-001').first().json;
const resp = $json;
const content = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
let parsed; try { parsed = JSON.parse(content); } catch(e){ parsed = { knowledgeUnits: [] }; }
const knowledgeUnits = parsed.knowledgeUnits || (Array.isArray(parsed)?parsed:[]);
return [{ json: { ...incoming, knowledge: { knowledgeUnits } } }];
